SELECT DISTINCT ON (d.ATRZ_DOC_ID)


WHERE COALESCE(d.DEL_YN, 'N') = 'N'
  AND d.CRNT_ATRZ_STEP_CD IN ('A204', 'A205', 'A206')
  AND (
      d.ATRZ_USER_ID = #{userId}
      OR EXISTS (
          SELECT 1
          FROM AUTHORIZATION_LINE al
          WHERE al.ATRZ_DOC_ID = d.ATRZ_DOC_ID
            AND al.ATRZ_APPR_USER_ID = #{userId}
      )
      OR EXISTS (
          SELECT 1
          FROM AUTHORIZATION_DOCUMENT_RECEIVER r
          WHERE r.ATRZ_DOC_ID = d.ATRZ_DOC_ID
            AND r.ATRZ_RCVR_ID = #{userId}
      )
  )
ORDER BY d.ATRZ_DOC_ID, d.ATRZ_SBMT_DT DESC

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM AUTHORIZATION_DOCUMENT d
WHERE d.ATRZ_DOC_ID = #{atrzDocId}
  AND COALESCE(d.DEL_YN, 'N') = 'N'
  AND (
      d.ATRZ_USER_ID = #{userId}
      OR EXISTS (
          SELECT 1
          FROM AUTHORIZATION_LINE al
          WHERE al.ATRZ_DOC_ID = d.ATRZ_DOC_ID
            AND al.ATRZ_APPR_USER_ID = #{userId}
      )
      OR EXISTS (
          SELECT 1
          FROM AUTHORIZATION_DOCUMENT_RECEIVER r
          WHERE r.ATRZ_DOC_ID = d.ATRZ_DOC_ID
            AND r.ATRZ_RCVR_ID = #{userId}
      )
  )
